function isNewSupabaseApiKey(value: string): boolean {
  return value.startsWith("sb_publishable_") || value.startsWith("sb_secret_");
}

function createSupabaseFetch(supabaseKey: string): typeof fetch {
  return (input, init) => {
    const headers = new Headers(
      typeof Request !== "undefined" && input instanceof Request ? input.headers : undefined,
    );

    if (init?.headers) {
      new Headers(init.headers).forEach((value, key) => headers.set(key, value));
    }

    // New Supabase API keys are opaque strings, not bearer JWTs.
    if (
      isNewSupabaseApiKey(supabaseKey) &&
      headers.get("Authorization") === `Bearer ${supabaseKey}`
    ) {
      headers.delete("Authorization");
    }

    headers.set("apikey", supabaseKey);
    return fetch(input, { ...init, headers });
  };
}

// ---------------------------------------------------------------------------
// "Remember me" storage adapter.
//
// Previously the login form had a "Remember me" checkbox that was checked
// by default, sent to nowhere, and did nothing — the client was hardcoded
// to `localStorage`, so every session persisted across browser restarts
// regardless of the checkbox. This adapter makes it real: unchecking it
// keeps the session in `sessionStorage` (cleared when the browser/tab
// closes) instead of `localStorage` (persists indefinitely). The choice is
// recorded under REMEMBER_FLAG_KEY *before* sign-in writes its session
// token, so this adapter can route that write to the right place.
// ---------------------------------------------------------------------------

const REMEMBER_FLAG_KEY = "taripon-remember-me";

export function setRememberPreference(remember: boolean) {
  try {
    localStorage.setItem(REMEMBER_FLAG_KEY, remember ? "1" : "0");
  } catch {
    // Ignore — storage may be unavailable (private browsing, disabled, etc).
  }
}

function rememberPreference(): boolean {
  try {
    return localStorage.getItem(REMEMBER_FLAG_KEY) !== "0";
  } catch {
    return true;
  }
}

function createRememberAwareStorage(): Storage {
  return {
    getItem: (key: string) => {
      try {
        return sessionStorage.getItem(key) ?? localStorage.getItem(key);
      } catch {
        return null;
      }
    },
    setItem: (key: string, value: string) => {
      try {
        if (rememberPreference()) {
          localStorage.setItem(key, value);
          sessionStorage.removeItem(key);
        } else {
          sessionStorage.setItem(key, value);
          localStorage.removeItem(key);
        }
      } catch {
        // Ignore — falls back to an in-memory session for this tab only.
      }
    },
    removeItem: (key: string) => {
      try {
        localStorage.removeItem(key);
        sessionStorage.removeItem(key);
      } catch {
        // Ignore.
      }
    },
    // Unused by supabase-js but required to satisfy the Storage interface.
    key: () => null,
    length: 0,
    clear: () => {
      try {
        localStorage.clear();
        sessionStorage.clear();
      } catch {
        // Ignore.
      }
    },
  };
}

